import{_ as a,o as i,c as e,a2 as r}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"1990年巴菲特致股东信核心要点","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1990年/核心总结.md","filePath":"01_letters/1990年/核心总结.md"}'),o={name:"01_letters/1990年/核心总结.md"};function t(h,l,n,u,s,d){return i(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="_1990年巴菲特致股东信核心要点" tabindex="-1">1990年巴菲特致股东信核心要点 <a class="header-anchor" href="#_1990年巴菲特致股东信核心要点" aria-label="Permalink to &quot;1990年巴菲特致股东信核心要点&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净资产增长3.62亿美元（7.3%）</li><li>每股账面价值从$19.46增长至$4,612.06</li><li>26年复合增长率：23.2%</li><li>预测&quot;未来三年至少有一年净值缩水&quot;得到验证</li></ul><hr><h2 id="市场波动与内在价值" tabindex="-1">市场波动与内在价值 <a class="header-anchor" href="#市场波动与内在价值" aria-label="Permalink to &quot;市场波动与内在价值&quot;">​</a></h2><h3 id="股价波动" tabindex="-1">股价波动 <a class="header-anchor" href="#股价波动" aria-label="Permalink to &quot;股价波动&quot;">​</a></h3><ul><li>1989年：内在价值增长&lt;账面价值增长&lt;市场涨幅（85%）</li><li>1990年：内在价值≈账面价值增长&gt;市场跌幅（-23%）</li><li>理想状态：股价围绕内在价值波动</li></ul><h3 id="四大重仓股" tabindex="-1">四大重仓股 <a class="header-anchor" href="#四大重仓股" aria-label="Permalink to &quot;四大重仓股&quot;">​</a></h3><ul><li>首都城市/ABC、可口可乐、GEICO、华盛顿邮报</li><li>年末价格比1989年稍具吸引力</li><li>媒体公司下跌，可口可乐上涨</li></ul><hr><h2 id="透视盈利-look-through-earnings" tabindex="-1">透视盈利（Look-Through Earnings） <a class="header-anchor" href="#透视盈利-look-through-earnings" aria-label="Permalink to &quot;透视盈利（Look-Through Earnings）&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>透视盈利 = 报告营业利润 + 投资企业留存盈利（伯克希尔占比） - 假设分配时的税</p><h3 id="重要性" tabindex="-1">重要性 <a class="header-anchor" href="#重要性" aria-label="Permalink to &quot;重要性&quot;">​</a></h3><ul><li>GAAP只记录收到的股息</li><li>留存盈利同样创造价值（如可口可乐回购股票提升持股比例）</li><li>真实经济收益的衡量</li></ul><h3 id="_1990年数据" tabindex="-1">1990年数据 <a class="header-anchor" href="#_1990年数据" aria-label="Permalink to &quot;1990年数据&quot;">​</a></h3><ul><li>透视盈利约5.9亿美元</li><li>目标：每年增长15%</li></ul><hr><h2 id="非保险运营" tabindex="-1">非保险运营 <a class="header-anchor" href="#非保险运营" aria-label="Permalink to &quot;非保险运营&quot;">​</a></h2><h3 id="整体表现" tabindex="-1">整体表现 <a class="header-anchor" href="#整体表现" aria-label="Permalink to &quot;整体表现&quot;">​</a></h3><ul><li>税后平均ROE：51%</li><li>无杠杆、设施自持、现金≈负债</li><li>财富500强前二十水平</li></ul><h3 id="_1-borsheim-s珠宝" tabindex="-1">1. Borsheim&#39;s珠宝 <a class="header-anchor" href="#_1-borsheim-s珠宝" aria-label="Permalink to &quot;1. Borsheim&#39;s珠宝&quot;">​</a></h3><ul><li>销售增长18%</li><li>美国单店珠宝店销量最大</li><li>honor system退货零损失</li></ul><h3 id="_2-内布拉斯加家具城" tabindex="-1">2. 内布拉斯加家具城 <a class="header-anchor" href="#_2-内布拉斯加家具城" aria-label="Permalink to &quot;2. 内布拉斯加家具城&quot;">​</a></h3><ul><li>销售1.59亿美元（增长4%）</li><li>美国最大单店家居店</li><li>卖喜诗糖果比加州喜诗店还多</li></ul><h3 id="_3-喜诗糖果" tabindex="-1">3. 喜诗糖果 <a class="header-anchor" href="#_3-喜诗糖果" aria-label="Permalink to &quot;3. 喜诗糖果&quot;">​</a></h3><ul><li>销量创纪录</li><li>利润率提高</li><li>阿尔伯克基店顾客抗议房东——品牌忠诚度</li></ul><h3 id="_4-水牛城新闻" tabindex="-1">4. 水牛城新闻 <a class="header-anchor" href="#_4-水牛城新闻" aria-label="Permalink to &quot;4. 水牛城新闻&quot;">​</a></h3><ul><li>行业困难：广告分散，定价权下降</li><li>收入仅降5%（同行降幅更大）</li><li>坚持50%以上新闻版面</li></ul><h3 id="_5-fechheimer" tabindex="-1">5. Fechheimer <a class="header-anchor" href="#_5-fechheimer" aria-label="Permalink to &quot;5. Fechheimer&quot;">​</a></h3><ul><li>乔治·赫尔德曼69岁退休</li><li>家族后代接续</li></ul><h3 id="_6-scott-fetzer" tabindex="-1">6. Scott Fetzer <a class="header-anchor" href="#_6-scott-fetzer" aria-label="Permalink to &quot;6. Scott Fetzer&quot;">​</a></h3><ul><li>Kirby三代吸尘器大卖</li><li>出口四年翻五倍，占比从5%到20%</li><li>世界图书百科海外持续增长</li></ul><hr><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="行业困境" tabindex="-1">行业困境 <a class="header-anchor" href="#行业困境" aria-label="Permalink to &quot;行业困境&quot;">​</a></h3><ul><li>保费增长仍低于10%要求</li><li>综合成本率继续恶化</li><li>破产公司继续运营，拉低行业价格</li></ul><h3 id="浮存金成本概念" tabindex="-1">浮存金成本概念 <a class="header-anchor" href="#浮存金成本概念" aria-label="Permalink to &quot;浮存金成本概念&quot;">​</a></h3><ul><li>真正衡量保险盈利能力的指标</li><li>浮存金成本 = 承保亏损 ÷ 平均浮存金</li></ul><h3 id="伯克希尔记录-1967-1990" tabindex="-1">伯克希尔记录（1967-1990） <a class="header-anchor" href="#伯克希尔记录-1967-1990" aria-label="Permalink to &quot;伯克希尔记录（1967-1990）&quot;">​</a></h3><ul><li>24年中有19年资金成本低于国债利率</li><li>11年资金成本为负（承保盈利）</li><li>1990年浮存金：16.37亿美元</li></ul><h3 id="巨灾再保险" tabindex="-1">巨灾再保险 <a class="header-anchor" href="#巨灾再保险" aria-label="Permalink to &quot;巨灾再保险&quot;">​</a></h3><ul><li>美国最大承保商</li><li>年保费约1亿</li><li>好年赚1亿，坏年亏2亿</li><li>宁要波动的15%，不要平稳的12%</li></ul><hr><h2 id="可交易证券" tabindex="-1">可交易证券 <a class="header-anchor" href="#可交易证券" aria-label="Permalink to &quot;可交易证券&quot;">​</a></h2><h3 id="新增投资-富国银行" tabindex="-1">新增投资：富国银行 <a class="header-anchor" href="#新增投资-富国银行" aria-label="Permalink to &quot;新增投资：富国银行&quot;">​</a></h3><ul><li>投资2.9亿美元，持股10%</li><li>喜欢管理层：卡尔·赖卡特和保罗·黑曾</li><li>成本远低于收购整个银行</li></ul><h3 id="对银行业的看法" tabindex="-1">对银行业的看法 <a class="header-anchor" href="#对银行业的看法" aria-label="Permalink to &quot;对银行业的看法&quot;">​</a></h3><ul><li>杠杆二十倍，小错误可吃掉全部股权</li><li>过去很多大银行犯大错</li><li>富国银行管理层理性、控制成本</li></ul><h3 id="rjr纳贝斯克债券" tabindex="-1">RJR纳贝斯克债券 <a class="header-anchor" href="#rjr纳贝斯克债券" aria-label="Permalink to &quot;RJR纳贝斯克债券&quot;">​</a></h3><ul><li>年底持有4.4亿美元</li><li>垃圾债多数是骗局——天生违约</li></ul><hr><h2 id="收购标准" tabindex="-1">收购标准 <a class="header-anchor" href="#收购标准" aria-label="Permalink to &quot;收购标准&quot;">​</a></h2><ol><li>大额，税后盈利至少1000万美元</li><li>历史盈利证明（不要预测、不要turnaround）</li><li>高ROE，负债少最好无负债</li><li>管理层在位（我们提供不了）</li><li>业务简单（太复杂技术不懂）</li><li>报价明确</li></ol><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><ol><li><p><strong>关于媒体行业</strong>：</p><blockquote><p>&quot;媒体特许经营权价值已下降，但我们不会卖。&quot;</p></blockquote></li><li><p><strong>关于保险</strong>：</p><blockquote><p>&quot;我们宁愿要波动的15%，不要平稳的12%。&quot;</p></blockquote></li><li><p><strong>关于投资</strong>：</p><blockquote><p>&quot;悲观带来低价，好公司降价才能买。&quot;</p></blockquote></li><li><p><strong>关于思考</strong>：</p><blockquote><p>&quot;伯特兰·罗素：大多数人宁愿死也不愿思考。&quot;</p></blockquote></li><li><p><strong>关于银行业</strong>：</p><blockquote><p>&quot;好银行关键是好管理层。&quot;</p></blockquote></li></ol><hr><h2 id="_1990年启示" tabindex="-1">1990年启示 <a class="header-anchor" href="#_1990年启示" aria-label="Permalink to &quot;1990年启示&quot;">​</a></h2><ol><li><strong>浮存金价值</strong>：低成本浮存金是保险业务核心竞争力</li><li><strong>逆向投资</strong>：悲观时有好价格，但要独立思考</li><li><strong>管理层决定成败</strong>：平庸行业配优秀管理者也能出色</li><li><strong>透视盈利</strong>：关注留存收益创造的真实价值</li><li><strong>接受波动</strong>：短期波动换取长期更高回报</li></ol>',60)])])}const b=a(o,[["render",t]]);export{q as __pageData,b as default};
